import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import ProjectList from '../components/Projects/ProjectList';
import TaskList from '../components/Tasks/TaskList';
import { useAuth } from '../context/AuthContext';
import '../styles/Dashboard.css';

const Dashboard = ({ 
  projects: propsProjects = null, 
  tasks: propsTasks = null, 
  users: propsUsers = null,
  setTasks: propsSetTasks = null
}) => {
  const { currentUser } = useAuth();
  const navigate = useNavigate();

  // Internal state (only used if no props provided)
  const [internalProjects, setInternalProjects] = useState([]);
  const [internalTasks, setInternalTasks] = useState([]);
  const [internalUsers, setInternalUsers] = useState([]);

  const [loading, setLoading] = useState(!propsProjects || !propsTasks || !propsUsers);
  const [error, setError] = useState('');

  // Use props if provided, otherwise use internal state
  const projects = propsProjects || internalProjects;
  const tasks = propsTasks || internalTasks;
  const users = propsUsers || internalUsers;
  const setTasks = propsSetTasks || setInternalTasks;

  useEffect(() => {
    // Only fetch data if no props were provided
    if (!propsProjects || !propsTasks || !propsUsers) {
      const fetchData = async () => {
        try {
          setLoading(true);
          // Mock data - in a real app, this would be an API call
          const mockUsers = [
            { id: 1, name: 'Wayne Travis', email: 'wayne@example.com', role: 'project_manager' },
            { id: 2, name: 'Sarah Johnson', email: 'sarah@example.com', role: 'team_lead' },
            { id: 3, name: 'Mike Chen', email: 'mike@example.com', role: 'developer' },
            { id: 4, name: 'Emily Rodriguez', email: 'emily@example.com', role: 'designer' }
          ];

          const mockProjects = [
            { 
              id: 1, 
              name: 'Website Redesign', 
              description: 'Complete redesign of company website with modern UI/UX',
              due_date: '2023-12-15',
              manager_id: 1,
              progress: 65,
              status: 'In Progress',
              priority: 'high',
              created_at: '2023-09-01',
              updated_at: '2023-09-25'
            },
            { 
              id: 2, 
              name: 'Mobile App Development', 
              description: 'Build cross-platform mobile application',
              due_date: '2024-01-30',
              manager_id: 2,
              progress: 30,
              status: 'In Progress',
              priority: 'high',
              created_at: '2023-09-15',
              updated_at: '2023-09-26'
            }
          ];

          const mockTasks = [
            {
              id: 1,
              title: 'Design Homepage',
              description: 'Create new homepage layout with improved UX',
              project_id: 1,
              assignee_id: 3,
              status: 'In Progress',
              priority: 'high',
              due_date: '2023-10-15',
              created_at: '2023-09-20',
              updated_at: '2023-09-25'
            },
            {
              id: 2,
              title: 'Implement Authentication',
              description: 'Set up user authentication system',
              project_id: 2,
              assignee_id: 3,
              status: 'Completed',
              priority: 'high',
              due_date: '2023-10-05',
              created_at: '2023-09-15',
              updated_at: '2023-09-24'
            }
          ];

          setInternalProjects(mockProjects);
          setInternalTasks(mockTasks);
          setInternalUsers(mockUsers);
        } catch (err) {
          console.error('Error fetching dashboard data:', err);
          setError('Failed to load dashboard data. Please try again later.');
        } finally {
          setLoading(false);
        }
      };

      fetchData();
    } else {
      // If props are provided, we're not loading
      setLoading(false);
    }
  }, [propsProjects, propsTasks, propsUsers]);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative" role="alert">
        <strong className="font-bold">Error: </strong>
        <span className="block sm:inline">{error}</span>
      </div>
    );
  }

  // Calculate statistics
  const stats = {
    totalProjects: projects.length,
    totalTasks: tasks.length,
    completedTasks: tasks.filter(task => task.status === 'Completed').length,
    inProgressTasks: tasks.filter(task => task.status === 'In Progress').length,
    myTasks: tasks.filter(task => currentUser && task.assignee_id === currentUser.id).length
  };

  const recentTasks = tasks.slice(0, 5);
  const myRecentTasks = tasks
    .filter(task => currentUser && task.assignee_id === currentUser.id)
    .slice(0, 3);

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Welcome back, {currentUser?.name || 'User'}! 👋</h1>
        <p>Here's what's happening with your projects today.</p>
      </div>

      {/* Statistics Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">📁</div>
          <div className="stat-content">
            <h3>{stats.totalProjects}</h3>
            <p>Total Projects</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-content">
            <h3>{stats.totalTasks}</h3>
            <p>Total Tasks</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🚀</div>
          <div className="stat-content">
            <h3>{stats.inProgressTasks}</h3>
            <p>In Progress</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🎯</div>
          <div className="stat-content">
            <h3>{stats.myTasks}</h3>
            <p>My Tasks</p>
          </div>
        </div>
      </div>

      <div className="dashboard-content">
        {/* My Recent Tasks */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>My Recent Tasks</h2>
            <button 
              onClick={() => navigate('/my-tasks')}
              className="btn btn-outline"
            >
              View All
            </button>
          </div>
          {myRecentTasks.length > 0 ? (
            <TaskList tasks={myRecentTasks} users={users} projects={projects} />
          ) : (
            <div className="empty-state">
              <p>No tasks assigned to you yet</p>
              <button 
                onClick={() => navigate('/tasks/new')}
                className="btn btn-primary mt-4"
              >
                Create your first task
              </button>
            </div>
          )}
        </section>

        {/* All Projects */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>All Projects</h2>
            <span className="project-count">{projects.length} projects</span>
          </div>
          {projects.length > 0 ? (
            <ProjectList projects={projects} users={users} />
          ) : (
            <div className="empty-state">
              <p>No projects created yet</p>
